// StringBuilder IS a Builder. toString() IS build().
String result = new StringBuilder()
    .append("Hello, ")
    .append(user.getName())
    .append("! You have ")
    .append(count)
    .append(" new messages.")
    .toString();  // build() -> immutable String

// Without Builder:
String result = "Hello, " + user.getName() + "! You have " + count + " new messages.";
// Creates 4 intermediate String objects (immutable = new object each +)

// Stream pipeline IS a Builder pattern!
List<String> result = users.stream()       // create builder
    .filter(u -> u.isActive())              // configure step 1
    .map(User::getName)                     // configure step 2
    .sorted()                               // configure step 3
    .collect(Collectors.toList());           // build() -> produce result

// Nothing executes until collect() (terminal operation = build())
// The pipeline is a LAZY BUILDER -- configures without executing.

// OkHttp uses Builder for every HTTP request
Request request = new Request.Builder()
    .url("https://api.example.com/users")
    .addHeader("Authorization", "Bearer " + token)
    .addHeader("Content-Type", "application/json")
    .post(RequestBody.create(json, JSON))
    .build();  // validates URL, creates immutable Request

// Why Builder? HTTP requests have:
// - Required: URL
// - Optional: headers, body, tags, cache control
// - Constraints: POST needs body, GET can't have body
// - Immutable after creation (thread-safe for async dispatch)

// Protobuf messages are ALWAYS built via Builder
Person person = Person.newBuilder()
    .setName("Alice")
    .setId(123)
    .setEmail("alice@example.com")
    .addPhones(
        Person.PhoneNumber.newBuilder()   // nested Builder!
            .setNumber("+1-555-0100")
            .setType(Person.PhoneType.MOBILE)
            .build()
    )
    .build();

// person is IMMUTABLE. To modify, create a new builder from it:
Person updated = person.toBuilder()
    .setEmail("alice.new@example.com")
    .build();

// Lombok generates the entire Builder class
@Builder
@Value  // makes all fields final + private + getters
public class Notification {
    String title;
    String body;
    String channel;
    String image;
    Priority priority;
}

// Generated usage:
Notification n = Notification.builder()
    .title("Hello")
    .body("World")
    .channel("push")
    .priority(Priority.HIGH)
    .build();

// To add validation, partially define the builder:
public static class NotificationBuilder {
    public Notification build() {
        if (title == null) throw new IllegalStateException("Title required");
        return new Notification(title, body, channel, image, priority);
    }
}

// Level 1: Build the HTTP client (reusable)
HttpClient client = HttpClient.newBuilder()
    .version(HttpClient.Version.HTTP_2)
    .connectTimeout(Duration.ofSeconds(10))
    .followRedirects(HttpClient.Redirect.NORMAL)
    .build();

// Level 2: Build each request
HttpRequest request = HttpRequest.newBuilder()
    .uri(URI.create("https://api.example.com/data"))
    .header("Accept", "application/json")
    .GET()
    .build();

// Two Builders, two products, used together
HttpResponse<String> response = client.send(request, BodyHandlers.ofString());
